INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(45, 15, 'Aprender sobre as últimas tendências em automação de processos e entender a visão de mercado para os próximos 5 anos.', 'Deep dive em RPA (Robotic Process Automation) e a ascensão de Low-Code/No-Code. Dados mostraram aumento de 40% na eficiência com implementação de IA.', 'Implementar um piloto de RPA no setor financeiro para faturamento e otimizar a criação de fluxos de trabalho utilizando plataformas Low-Code.', 'Palestrante: Dr. Ana Ribeiro. Referências: Artigo "The Future of Work" da Gartner. Link: https://rpa.conference.com/slides.pdf', 9, 'Evento muito bem organizado, conteúdo prático e aplicável.', 'https://certificados.empresa.com/15_45.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(43, 29, 'Buscar novos métodos ágeis de desenvolvimento de software e aprofundar conhecimento em arquitetura de microsserviços escaláveis.', 'Tópicos de Domain-Driven Design (DDD) aplicados a microsserviços. Foco na comunicação assíncrona usando filas de mensagens (RabbitMQ/Kafka).', 'Revisar a arquitetura atual do nosso produto principal, introduzindo o conceito de Bounded Contexts e explorando a adoção de Kafka para eventos críticos.', 'Palestrante principal: João Silva (Tech Lead na Innovate Solutions). Livro recomendado: "Building Microservices" de Sam Newman.', 8, 'Ótimo nível técnico, porém a parte de networking foi um pouco curta.', 'https://certificados.empresa.com/29_43.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(48, 36, 'Entender as diretrizes de compliance em LGPD e as melhores práticas para a gestão de riscos e privacidade de dados.', 'Revisão das penalidades da LGPD e as exigências para o mapeamento de dados pessoais. Insights sobre auditorias internas e externas.', 'Criar um comitê de privacidade interno para realizar auditorias trimestrais e atualizar todos os termos de consentimento no sistema legacy.', 'Empresa citada: AuditCorp. Referência legal: Lei Geral de Proteção de Dados (13.709/2018).', 10, 'Essencial para a área. Conteúdo claro e 100% focado em nossa realidade.', 'https://certificados.empresa.com/36_48.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(25, 40, 'Conhecer ferramentas modernas de análise de dados e visualização que auxiliem na tomada de decisões estratégicas.', 'Apresentação detalhada sobre o uso do Power BI e Tableau. Demonstração de modelos preditivos simples usando Python (bibliotecas Pandas e Scikit-learn).', 'Treinar a equipe no uso do Tableau para criação de dashboards executivos e iniciar a POC de um modelo de previsão de churn.', 'Palestrante: Maria Oliveira (Data Scientist). Link para o dataset: https://data.analytics.org/dados.csv', 7, 'O conteúdo de Power BI foi básico, mas o de modelos preditivos foi excelente.', 'https://certificados.empresa.com/40_25.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(18, 43, 'Explorar as novidades em segurança da informação, com foco em prevenção de ataques de phishing e ransomware.', 'Novas técnicas de engenharia social utilizadas em ataques recentes. Estratégias de Defesa em Profundidade (Defense in Depth) e segmentação de rede.', 'Atualizar o treinamento de segurança para todos os colaboradores, incluindo simulações de phishing mais sofisticadas e reforçar o backup imutável.', 'Relatório da CyberSec Trends 2024. Palco Principal: Apresentação de "Zero Trust Architecture".', 9, 'Evento de alta relevância, com informações que precisam ser implementadas urgentemente.', 'https://certificados.empresa.com/43_18.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(3, 27, 'Imersão em liderança de equipes remotas, focando em engajamento, produtividade e bem-estar do time.', 'Métricas de produtividade para trabalho remoto. Dicas para comunicação assíncrona eficaz e manutenção da cultura organizacional à distância.', 'Ajustar o cronograma de reuniões para otimizar o tempo de foco e implementar ferramentas de comunicação para reduzir a dependência de e-mail.', 'Palestrante: Carlos Mendes, autor de "Remote Team Excellence". Plataforma citada: Slack.', 8, 'Abordagem prática, gostei dos exemplos de gestão de tempo e priorização.', 'https://certificados.empresa.com/27_3.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(40, 26, 'Entender o futuro do marketing digital, com ênfase em SEO para pesquisa por voz e campanhas de vídeo de curta duração.', 'Aumento da importância do E-E-A-T (Experience, Expertise, Authoritativeness, Trustworthiness) no Google. Crescimento do TikTok e Reels como canais de conversão.', 'Revisar a estratégia de conteúdo focada em formato de perguntas e respostas para otimizar para voz e alocar mais budget para a produção de vídeos curtos.', 'Ferramenta citada: SEMRush. Artigo: "Voice Search Optimization" de Moz.', 7, 'Excelente para a área de Marketing. Muitos insights práticos de SEO.', 'https://certificados.empresa.com/26_40.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(38, 47, 'Melhorar habilidades de negociação e fechamento de grandes contratos (Enterprise Sales).', 'Técnicas de mapeamento de stakeholders e criação de Business Cases convincentes. Foco em negociação baseada em valor, não em preço.', 'Aplicar o novo script de descoberta de necessidades em grandes clientes e estruturar propostas que destaquem o ROI (Retorno sobre Investimento).', 'Livro: "The Challenger Sale". Instrutor: Ricardo Sales.', 9, 'Negociação complexa é meu ponto fraco, aprendi muito sobre como influenciar o comitê decisório.', 'https://certificados.empresa.com/47_38.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(26, 12, 'Adquirir conhecimento em metodologias de design thinking para inovação de produto e criação de MVPs (Minimum Viable Products).', 'As cinco etapas do Design Thinking (empatia, definição, ideação, prototipagem e teste). Como validar hipóteses rapidamente com baixo custo.', 'Integrar workshops de design thinking no início de todo novo projeto e criar um "Innovation Lab" para prototipagem rápida de novas funcionalidades.', 'Empresa: IDEO. Ferramenta de prototipagem: Figma.', 8, 'A parte de ideação foi a mais rica, com dinâmicas muito criativas.', 'https://certificados.empresa.com/12_26.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(45, 22, 'Explorar as tendências de User Experience (UX) e User Interface (UI) para aplicativos móveis.', 'A importância da acessibilidade (WCAG) no design de interfaces. Novas abordagens para microinterações e feedback tátil.', 'Revisar a interface do nosso aplicativo para garantir 100% de conformidade com WCAG e implementar testes de usabilidade com usuários com deficiência visual.', 'Referência: Google Material Design Guidelines. Designer: Sofia Lins.', 10, 'Conteúdo de altíssima qualidade. O foco em acessibilidade é fundamental e muito bem-vindo.', 'https://certificados.empresa.com/22_45.pdf');
INSERT INTO Certificado_participacao (Evento_id, Colaborador_id, objetivo, principais_infos, aplicacoes, referencias, avaliacao, comentarios, url_pdf) VALUES
(2, 42, 'Aprender sobre o uso de computação em nuvem (Cloud Computing) para infraestrutura de alta disponibilidade e custo-benefício.', 'Comparativo entre AWS, Azure e GCP. Tópicos de Serverless e contêineres (Docker e Kubernetes).', 'Migrar o ambiente de homologação para uma arquitetura Serverless e começar o treinamento em Kubernetes para a equipe de DevOps.', 'Plataformas citadas: AWS, Azure. Certificação: Exame AWS Certified Solutions Architect.', 9, 'Tirou muitas dúvidas sobre a migração para a nuvem. O comparativo de custos foi muito útil.', 'https://certificados.empresa.com/42_2.pdf');
